def perceive(data):
    # Ingest a portfolio snapshot of `bucket=amount` lines into the aging book,
    # e.g. "current=12000\n30=4000\n90=1500". Unknown buckets are ignored.
    known = {"current", "30", "60", "90", "120plus"}
    buckets = {}
    for line in str(data).strip().splitlines():
        if "=" not in line:
            continue
        key, value = line.split("=", 1)
        key = key.strip()
        if key not in known:
            continue
        try:
            buckets[key] = round(float(value.strip()), 2)
        except (ValueError, TypeError):
            continue
    return {"buckets": buckets}
